export default function AppIcon({ type, icon, size = 34, className = '' }) {
  if (type === 'generic' || !ICONS[type]) {
    const gi = GENERIC_ICONS[icon];
    if (gi) {
      return (
        <svg
          className={`shrink-0 ${className}`}
          width={size}
          height={size}
          viewBox="0 0 24 24"
          fill={gi.color}
          xmlns="http://www.w3.org/2000/svg"
        >
          <path d={gi.path} />
        </svg>
      );
    }
    const def = GENERIC_ICONS.grid;
    return (
      <svg
        className={`shrink-0 ${className}`}
        width={size}
        height={size}
        viewBox="0 0 24 24"
        fill={def.color}
        xmlns="http://www.w3.org/2000/svg"
      >
        <path d={def.path} />
      </svg>
    );
  }

  const data = ICONS[type];

  return (
    <svg
      className={`shrink-0 ${className}`}
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill={data.stroke ? 'none' : data.color}
      stroke={data.stroke ? data.color : 'none'}
      strokeWidth={data.stroke ? 2.2 : 0}
      strokeLinecap="round"
      strokeLinejoin="round"
      xmlns="http://www.w3.org/2000/svg"
    >
      <path d={data.path} />
    </svg>
  );
}

export function getAppTypeColor(type) {
  return ICONS[type]?.color || GENERIC_ICONS.grid.color;
}

export const APP_TYPE_ICONS = Object.keys(ICONS);
